column4:
{
  "category": "Produce",
  "typical_unit": "each (or per lb)",
  "storage_tip": "Unopened: store at room temperature until ripe; once ripe, refrigerate to slow further ripening (peel may darken). Unopened/Uncut: keep in a ventilated spot away from very cold areas.",
  "nutrition_note": "Naturally sweet and potassium-rich; also provides vitamin B6 and fiber—great for quick energy."
}

{
  "category": "Condiments",
  "typical_unit": "8–16 oz (225–450 g) tub or jar",
  "storage_tip": "Unopened: store in a cool, dry pantry. Opened: refrigerate and keep the lid tightly closed; stir before use and use within a few months for best flavor.",
  "nutrition_note": "Distinctive spicy-sweet fermented chili paste that’s especially rich in flavor from chili, fermentation, and often a bit of sugar; like many condiments, it can be relatively high in sodium—check the label if you’re monitoring salt."
}

{
  "category": "Produce",
  "typical_unit": "14–16 oz (400–450 g) block, or 8–16 oz (225–450 g) tub",
  "storage_tip": "Unopened: keep refrigerated in its sealed package (often submerged in liquid). Opened: keep in a fresh container of water or drain and store in an airtight container; refrigerate and use within about 3–5 days (for best quality). Freeze only for firmer/crumblier texture after thawing.",
  "nutrition_note": "Tofu’s most distinctive trait is that it’s a high-protein soy food that comes in soft to extra-firm textures—great for absorbing flavors while providing substantial plant-based protein and calcium (especially if made with calcium sulfate)."
}
